"use client"

import { createContext, useReducer } from "react"
import axios from "axios"
import profileReducer from "./profileReducer"

// Initial state
const initialState = {
  profile: null,
  profiles: [],
  githubStats: null,
  mediumArticles: null,
  loading: true,
  error: null,
}

// Create context
export const ProfileContext = createContext(initialState)

// Provider component
export const ProfileProvider = ({ children }) => {
  const [state, dispatch] = useReducer(profileReducer, initialState)

  // Get current user's profile
  const getCurrentProfile = async () => {
    try {
      const res = await axios.get("/api/profiles")

      dispatch({
        type: "GET_PROFILE",
        payload: res.data.data,
      })
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })
    }
  }

  // Get all profiles
  const getProfiles = async () => {
    try {
      const res = await axios.get("/api/profiles/all")

      dispatch({
        type: "GET_PROFILES",
        payload: res.data.data,
      })
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })
    }
  }

  // Get profile by ID
  const getProfileById = async (id) => {
    try {
      const res = await axios.get(`/api/profiles/${id}`)

      dispatch({
        type: "GET_PROFILE",
        payload: res.data.data,
      })
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })
    }
  }

  // Create or update profile
  const createProfile = async (formData, edit = false) => {
    try {
      const config = {
        headers: {
          "Content-Type": "application/json",
        },
      }

      const res = await axios.post("/api/profiles", formData, config)

      dispatch({
        type: "GET_PROFILE",
        payload: res.data.data,
      })

      return {
        success: true,
        msg: edit ? "Profile Updated" : "Profile Created",
      }
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })

      return {
        success: false,
        msg: err.response.data.error,
      }
    }
  }

  // Add platform
  const addPlatform = async (platformData) => {
    try {
      const config = {
        headers: {
          "Content-Type": "application/json",
        },
      }

      const res = await axios.post("/api/profiles/platform", platformData, config)

      dispatch({
        type: "UPDATE_PROFILE",
        payload: res.data.data,
      })

      return {
        success: true,
        msg: "Platform Added",
      }
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })

      return {
        success: false,
        msg: err.response.data.error,
      }
    }
  }

  // Delete platform
  const deletePlatform = async (id) => {
    try {
      const res = await axios.delete(`/api/profiles/platform/${id}`)

      dispatch({
        type: "UPDATE_PROFILE",
        payload: res.data.data,
      })

      return {
        success: true,
        msg: "Platform Removed",
      }
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response.data.error,
      })

      return {
        success: false,
        msg: err.response.data.error,
      }
    }
  }

  // Get GitHub stats
  const getGithubStats = async () => {
    try {
      const res = await axios.get("/api/github/stats")

      dispatch({
        type: "GET_GITHUB_STATS",
        payload: res.data.data,
      })
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response?.data?.error || "Error fetching GitHub stats",
      })
    }
  }

  // Get Medium articles
  const getMediumArticles = async () => {
    try {
      const res = await axios.get("/api/medium/articles")

      dispatch({
        type: "GET_MEDIUM_ARTICLES",
        payload: res.data.data,
      })
    } catch (err) {
      dispatch({
        type: "PROFILE_ERROR",
        payload: err.response?.data?.error || "Error fetching Medium articles",
      })
    }
  }

  // Clear profile
  const clearProfile = () => dispatch({ type: "CLEAR_PROFILE" })

  return (
    <ProfileContext.Provider
      value={{
        profile: state.profile,
        profiles: state.profiles,
        githubStats: state.githubStats,
        mediumArticles: state.mediumArticles,
        loading: state.loading,
        error: state.error,
        getCurrentProfile,
        getProfiles,
        getProfileById,
        createProfile,
        addPlatform,
        deletePlatform,
        getGithubStats,
        getMediumArticles,
        clearProfile,
      }}
    >
      {children}
    </ProfileContext.Provider>
  )
}
